const p = $input.first().json;

if (!p.os_codigo && !p.tecnico_id) {
  throw new Error('os_codigo OU tecnico_id é obrigatório para buscar contexto.');
}

return [{ json: {
  os_codigo: p.os_codigo ? String(p.os_codigo) : null,
  tecnico_id: p.tecnico_id ? String(p.tecnico_id) : null,
  busca_por: p.os_codigo ? 'os_codigo' : 'tecnico_id'
}}];

const os = $input.first().json;
const p = $('Validar Params').first().json;

// Se não encontrou (item vazio do alwaysOutputData)
if (!os || !os.os_codigo) {
  return [{ json: {
    encontrado: false,
    os_codigo: p.os_codigo || null,
    tecnico_id: p.tecnico_id || null,
    mensagem: p.os_codigo
      ? `Nenhuma OS encontrada com código ${p.os_codigo}.`
      : `Nenhuma OS ativa encontrada para o técnico.`,
    contexto: null,
    produtos: [],
    servicos: []
  }}];
}

// Parsear produtos e serviços do JSONB
let produtos = [];
let servicos = [];
try { produtos = typeof os.produtos_json === 'string' ? JSON.parse(os.produtos_json) : (os.produtos_json || []); } catch(e) {}
try { servicos = typeof os.servicos_json === 'string' ? JSON.parse(os.servicos_json) : (os.servicos_json || []); } catch(e) {}

// Verificar se está pronto para fechar
const problemas = [];
if (!os.cliente_codigo) problemas.push('Cliente sem código oficial');
if (!os.defeito) problemas.push('Defeito não informado');
if (!os.solucao) problemas.push('Solução não informada');
if (!os.tipo_pagamento && !os.em_garantia) problemas.push('Forma de pagamento não definida');

const resumo = [
  `OS #${os.os_codigo}`,
  `Cliente: ${os.cliente_nome || 'não identificado'} (cód: ${os.cliente_codigo || 'pendente'})`,
  `Técnico: ${os.tecnico_nome || 'não identificado'}`,
  `Status: ${os.status_os} | Fase: ${os.fase_ia}`,
  `Defeito: ${os.defeito || 'não informado'}`,
  `Causa: ${os.causa || 'não informada'}`,
  `Solução: ${os.solucao || 'não informada'}`,
  `Garantia: ${os.em_garantia ? 'SIM' : 'NÃO'}`,
  `Pagamento: ${os.tipo_pagamento || 'não definido'}`,
  `Entrada: ${os.hora_entrada || 'não registrada'}`,
  `Saída: ${os.hora_saida || 'não registrada'}`,
  `Evidências: ${os.qtd_evidencias || 0}`,
  `Produtos: ${produtos.length}`,
  `Serviços: ${servicos.length}`
].join('\n');

return [{ json: {
  encontrado: true,
  os_codigo: os.os_codigo,
  os_id_bomsaldo: os.os_id_bomsaldo,
  status_os: os.status_os,
  fase_ia: os.fase_ia,
  pronto_para_fechar: problemas.length === 0,
  problemas_encontrados: problemas,
  contexto: os,
  produtos,
  servicos,
  resumo
}}];
